'use server'

import axios from 'axios';
import https from 'https';
import * as xlsx from 'xlsx';
import fs from 'fs';
import path from 'path';

type PerangkatDaerah = {
    No: string,
    kodeLokasi: string,
    namaLokasi: string,
    jabatan: string,
    action: string,
}

export type Barang = {
    // --- IDENTITAS UTAMA ---
    no: number | null;               // Source: __EMPTY    (Kolom A / Index 0)
    perangkatDaerah: string | null;  // Source: __EMPTY_1  (Kolom B / Index 1)
    nibar: string | null;            // Source: __EMPTY_2  (Kolom C / Index 2) - Nomor Induk Barang
    kodeBarang: string | null;       // Source: __EMPTY_3  (Kolom D / Index 3)
    namaBarang: string | null;       // Source: __EMPTY_4  (Kolom E / Index 4)
    nomorRegister: string | null;    // Source: __EMPTY_5  (Kolom F / Index 5)

    // --- SPESIFIKASI BARANG (KIB B) ---
    merkType: string | null;         // Source: __EMPTY_6  (Kolom G / Index 6)
    ukuranCc: string | null;         // Source: __EMPTY_7  (Kolom H / Index 7)
    bahan: string | null;            // Source: __EMPTY_8  (Kolom I / Index 8)
    tahunPembelian: string | null;   // Source: __EMPTY_9  (Kolom J / Index 9)

    // --- NOMOR IDENTIFIKASI (Kendaraan/Mesin) ---
    nomorPabrik: string | null;      // Source: __EMPTY_10 (Kolom K / Index 10)
    nomorRangka: string | null;      // Source: __EMPTY_11 (Kolom L / Index 11)
    nomorMesin: string | null;       // Source: __EMPTY_12 (Kolom M / Index 12)
    nomorPolisi: string | null;      // Source: __EMPTY_13 (Kolom N / Index 13)
    nomorBpkb: string | null;        // Source: __EMPTY_14 (Kolom O / Index 14)

    // --- STATUS & NILAI ASET ---
    asalUsul: string | null;         // Source: __EMPTY_15 (Kolom P / Index 15)
    harga: number | null;            // Source: __EMPTY_16 (Kolom Q / Index 16)
    kondisi: string | null;          // Source: __EMPTY_17 (Kolom R / Index 17) - (B/KB/RB)
    jumlah: number | null;           // Source: __EMPTY_18 (Kolom S / Index 18)
    keterangan: string | null;       // Source: __EMPTY_19 (Kolom T / Index 19)
}

