export async function actionExtractDaftarBarang(kodeLokasi: string, namaLokasi: string) {
    const config = {
        httpsAgent: new https.Agent({ family: 4, rejectUnauthorized: false, keepAlive: true }),
        responseType: 'arraybuffer' as const,
        timeout: 60000,
        maxContentLength: 50 * 1024 * 1024,
    }
    try {
        const postResponse = await axios.post(
            'https://ebmd.pasuruankab.go.id/ebmd_rpt/AST_daftarbarang/dbpb_param.aspx',
            new URLSearchParams({
                '__EVENTTARGET': '',
                '__EVENTARGUMENT': '',
                '__LASTFOCUS': '',
                '__VIEWSTATE': '',
                '__VIEWSTATEGENERATOR': '0E8F9E58',
                '__EVENTVALIDATION': '',
                'ctl00$Isi$DdlThn': '2026',
                'ctl00$Isi$DdlJnsAset': '1',
                'ctl00$Isi$DdlPeriodeLap': '23',
                'ctl00$Isi$DdlIe': '0',
                'ctl00$Isi$RdTutup': '1',
                'ctl00$Isi$DdlOrg': '7',
                'ctl00$Isi$DdlPB': '04.00.00',
                'ctl00$Isi$TxtTglTtd': '23/05/2026',
                'ctl00$Isi$DdlPegKanan': '0',
                'ctl00$Isi$TxtJabKanan': '',
                'ctl00$Isi$Button2': 'Export Ke Excel'
            }),
            {
                params: {
                    'kib': '1',
                    'Periode': '2026',
                    'isskpd': '1',
                    'usrid': '884'
                },
                headers: {
                    'accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,image/apng,*/*;q=0.8,application/signed-exchange;v=b3;q=0.7',
                    'accept-language': 'en-US,en;q=0.9,id;q=0.8',
                    'cache-control': 'max-age=0',
                    'origin': 'https://ebmd.pasuruankab.go.id',
                    'priority': 'u=0, i',
                    'referer': 'https://ebmd.pasuruankab.go.id/ebmd_rpt/AST_daftarbarang/dbpb_param.aspx?kib=1&Periode=2026&isskpd=1&usrid=884',
                    'sec-ch-ua': '"Chromium";v="148", "Google Chrome";v="148", "Not/A)Brand";v="99"',
                    'sec-ch-ua-mobile': '?0',
                    'sec-ch-ua-platform': '"Windows"',
                    'sec-fetch-dest': 'document',
                    'sec-fetch-mode': 'navigate',
                    'sec-fetch-site': 'same-origin',
                    'sec-fetch-user': '?1',
                    'upgrade-insecure-requests': '1',
                    'user-agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/148.0.0.0 Safari/537.36',
                    'cookie': '_ga=GA1.3.1310505215.1777637860; _gid=GA1.3.951371392.1779099639; ebmdpasuruan_session=a%3A21%3A%7Bs%3A10%3A%22session_id%22%3Bs%3A32%3A%2270f35bd05643c9ee7123997a1081b68d%22%3Bs%3A10%3A%22ip_address%22%3Bs%3A13%3A%2236.78.109.182%22%3Bs%3A10%3A%22user_agent%22%3Bs%3A111%3A%22Mozilla%2F5.0+%28Windows+NT+10.0%3B+Win64%3B+x64%29+AppleWebKit%2F537.36+%28KHTML%2C+like+Gecko%29+Chrome%2F148.0.0.0+Safari%2F537.36%22%3Bs%3A13%3A%22last_activity%22%3Bi%3A1779506062%3Bs%3A9%3A%22user_data%22%3Bs%3A0%3A%22%22%3Bs%3A7%3A%22user_id%22%3Bi%3A884%3Bs%3A8%3A%22username%22%3Bs%3A16%3A%22adminfernanda106%22%3Bs%3A8%3A%22group_id%22%3Bi%3A2%3Bs%3A8%3A%22is_admin%22%3Bi%3A1%3Bs%3A12%3A%22IsSuperAdmin%22%3BN%3Bs%3A9%3A%22logintime%22%3Bs%3A23%3A%222026-05-22+13%3A24%3A53.000%22%3Bs%3A6%3A%22org_id%22%3Bi%3A71%3Bs%3A10%3A%22kodelokasi%22%3Bs%3A8%3A%2229.00.00%22%3Bs%3A8%3A%22lokasiid%22%3Bi%3A839%3Bs%3A5%3A%22tahun%22%3Bi%3A2026%3Bs%3A11%3A%22ispengelola%22%3Bi%3A0%3Bs%3A9%3A%22secretkey%22%3Bs%3A88%3A%22ZVgTv5n6zH8wu%2BPwsAWcpdKkPx5RTS9c0Hm8Nt1jrVfW2xt9T%2BM600Mj98a3xMLucxXN8KMIvyB9bSdZQPZ8cw%3D%3D%22%3Bs%3A4%3A%22nama%22%3Bs%3A32%3A%22FERNANDA+AKHSANUDDIN+.A%2C+A.Md.M.%22%3Bs%3A10%3A%22pegawai_id%22%3Bs%3A21%3A%2219991010+202201+1+002%22%3Bs%3A9%3A%22groupname%22%3Bs%3A6%3A%22Admin+%22%3Bs%3A9%3A%22logged_in%22%3Bb%3A1%3B%7Dfebac64cf706e7922f4eec109ecde1f7517e999a; _ga_3LFLRFSZV4=GS2.3.s1779506076$o19$g0$t1779506076$j60$l0$h0'
                },
                ...config
            }
        );

        // Validasi jika server membalas HTML (biasanya Error 500 atau Sesi Habis)
        const contentType = postResponse.headers['content-type'];
        if (typeof contentType === 'string' && (contentType.includes('text/html') || contentType.includes('text/plain'))) {
            const htmlString = Buffer.from(postResponse.data).toString('utf-8');

            // Jika isinya sangat pendek (misal pesan error), simpan untuk debug
            if (htmlString.length < 5000) {
                const debugPath = path.join(process.cwd(), 'debug-ebmd-error.html');
                fs.writeFileSync(debugPath, htmlString);
                return { success: false, error: "Server mengembalikan HTML, kemungkinan sesi habis. Cek debug-ebmd-error.html" };
            }
        }

        // console.log("Excel biner berhasil diterima. Mulai proses penyimpanan...");

        // TAHAP 1.5: SIMPAN FILE RAW KE DISK (Untuk verifikasi manual)
        const buffer = Buffer.from(postResponse.data);
        // const fileName = `debug_bmd_${Date.now()}.xlsx`;
        // const filePath = path.join(process.cwd(), fileName); // Disimpan di root project

        // fs.writeFileSync(filePath, buffer);
        // console.log(`File berhasil disimpan di: ${filePath}`);

        // TAHAP 2: PARSING (Seperti sebelumnya)
        const workbook = xlsx.read(buffer, { type: 'buffer' });
        const firstSheetName = workbook.SheetNames[0];

        // Gunakan range: 9 untuk skip 9 baris header yang kosong/metadata
        const rawData = xlsx.utils.sheet_to_json(workbook.Sheets[firstSheetName], {
            range: 9,
            defval: null
        });

        // Sekarang kita mengonversi cleanedData ke plain object JSON, bukan rawData lagi
        const parsedData = JSON.parse(JSON.stringify(rawData))
        const sanitizedData = parsedData.filter((d: any) => d['__EMPTY_7'] !== null);

        const formattedData = sanitizedData.map((row: any) => ({
            perangkatDaerah: "Dinas Pendidikan",
            nibar: row['__EMPTY_11'] ?? null,
            nomorRegister: row['__EMPTY_12'] ?? null,
            kodeBarang: `${row['__EMPTY']}.${row['__EMPTY_1']}.${row['__EMPTY_2']}.${row['__EMPTY_3']}.${row['__EMPTY_4']}.${row['__EMPTY_5']}.${row['__EMPTY_7']}`,
            namaBarang: row['__EMPTY_8'] ?? null,
            spesifikasiNamaBarang: row['__EMPTY_13'] ?? null,
            spesifikasiLainnya: row['_EMPTY_14'] ?? null,
            jumlah: row['__EMPTY_16'] ?? null,
            satuan: row['__EMPTY_17'] ?? null,
            lokasi: row['__EMPTY_18'] ?? null,
            // merkType: row['__EMPTY_6'] ?? null,
            // ukuranCc: row['__EMPTY_7'] ?? null,
            // bahan: row['__EMPTY_8'] ?? null,
            // tahunPembelian: row['__EMPTY_9'] ?? null,
            // nomorPabrik: row['__EMPTY_10'] ?? null,
            // nomorRangka: row['__EMPTY_11'] ?? null,
            // nomorMesin: row['__EMPTY_12'] ?? null,
            // nomorPolisi: row['__EMPTY_13'] ?? null,
            // nomorBpkb: row['__EMPTY_14'] ?? null,
            // asalUsul: row['__EMPTY_15'] ?? null,
            // harga: row['__EMPTY_16'] ?? null,
            // kondisi: row['__EMPTY_17'] ?? null,
            // jumlah: row['__EMPTY_18'] ?? null,
            // keterangan: row['__EMPTY_19'] ?? null
        }));

        return {
            success: true,
            count: formattedData.length,
            rawData: parsedData,
            data: formattedData // Data yang dikirim sudah cantik dan sesuai Type!
        };
    } catch (error: any) {
        return { success: false, error: error.message };
    }
}